-- ---------- Oportunidades (1 por conta; estágio derivado da temperatura) ----------
-- Trigger desligado no carregamento em massa; o baseline do funil é semeado
-- explicitamente mais abaixo (senão os contatos contariam em dobro).
alter table oportunidades disable trigger trg_log_pipeline_evento;
alter table oportunidades enable trigger trg_log_pipeline_evento;

-- ---------- Contatos (decisor/gatekeeper quando há) ----------

-- ---------- Interações (primeiro contato WhatsApp / visita) ----------

-- ---------- Tracking semanal: baseline do funil nas DATAS REAIS de contato ----------
-- Daqui pra frente o trigger registra cada mudança de estágio sozinho (data real BRT).
  select o.id,o.canal_id,'contatado'::estagio_oport,coalesce(ct.data_primeiro_contato,o.data_entrada_estagio)
    from oportunidades o join contas ct on ct.id=o.conta_id where o.estagio<>'cadastrado'
  union all
  select o.id,o.canal_id,'reuniao'::estagio_oport,coalesce(ct.data_primeiro_contato,o.data_entrada_estagio)
    from oportunidades o join contas ct on ct.id=o.conta_id where o.estagio in ('reuniao','proposta','negociacao','fechado_ganho')
  union all
  select o.id,o.canal_id,'fechado_ganho'::estagio_oport,coalesce(ct.data_primeiro_contato,o.data_entrada_estagio)
    from oportunidades o join contas ct on ct.id=o.conta_id where o.estagio='fechado_ganho';

commit;

-- Snapshot inicial do tracking semanal (daqui pra frente o pg_cron captura toda
-- sexta 18h BRT; a UI também tem "Capturar agora").
select capturar_snapshot_semanal('baseline');

